sql:
SELECT COUNT(*) 
FROM font_files 
WHERE project_key = 2 AND license_key = 'ABC123';

SELECT uploaded_by, COUNT(file_id) AS number_of_files 
FROM font_files 
GROUP BY uploaded_by;

SELECT file_name, created_at
FROM font_files
WHERE created_at = (SELECT MAX(created_at) FROM font_files);

SELECT file_format, license_key, SUM(file_size) as total_size
FROM font_files
GROUP BY file_format, license_key;

SELECT p.project_name, ff.file_name
FROM font_files ff
JOIN projects p ON ff.project_key = p.project_id;

SELECT definition_name
FROM font_definitions
WHERE is_italic = 1;

